mapper.select:
SELECT thr.id id, thr.order_num orderNum, thr.total_price totalPrice, thr.pay_type payType, thrl.status status, thrl.create_time createTime, o.pay_order_num payOrderNum, ths.name hosSickName, th.hos_name hospitalName, tdu.name doctorName FROM t_hos_revisit_log thrl left join t_hos_revisit thr on thrl.hos_revisit_id=thr.id left join t_order o on thr.order_num = o.order_num left join t_hos_sick ths on thrl.sick_id=ths.id left join t_doctor_user tdu on thrl.doctor_user_id=tdu.id left join t_hospital th on tdu.hospital_id=th.id
order by thrl.create_time desc
LIMIT #{page} ,#{limit}
